def explain_flags(defaults: dict[str, bool], segments: dict[str, dict[str, bool]], user: dict) -> dict[str, dict]:
    explained = {
        key: {"value": value, "source": "default"}
        for key, value in defaults.items()
    }
    for segment_name in user.get("segments", []):
        for key, value in segments.get(segment_name, {}).items():
            explained[key] = {"value": value, "source": f"segment:{segment_name}"}
    for key, value in user.get("overrides", {}).items():
        explained[key] = {"value": value, "source": "user_override"}
    return explained

